//! fat-station-flow — aeon-flow framed variant of `fat-station-uds.rs`.
//!
//! Why this exists
//! ----------------
//! `fat-station-uds.rs` proved that UDS + length-prefixed framing
//! collapses the per-call floor for local mesh inference. But its frame
//! format ("4-byte length + ASCII headers + blank line + body") is
//! bespoke — it doesn't unify with the rest of the aeon ecosystem.
//!
//! Aeon already speaks a binary `FlowCodec` (10-byte header) over
//! WebSocket between distributed-inference workers. UDP transports use
//! the same header. By moving fat-station onto that same wire format,
//! ONE codec spans every transport: UDS today, UDP datagrams next,
//! WebSocket on workers, and any future transport (kqueue eventfd,
//! shared-memory ring, etc.). The kernel call surface and per-frame
//! semantics are identical — only the bytes coming off the socket
//! change.
//!
//! Wire format (mirrors `open-source/aeon/src/flow/FlowCodec.ts`)
//! --------------------------------------------------------------
//! Each request and each response is exactly one aeon-flow frame:
//!
//!   Header (10 bytes, big-endian throughout):
//!     [0..1]  stream_id  u16   ROUTE OPCODE (see ROUTE_* constants below)
//!     [2..5]  sequence   u32   per-request id (echoed in response)
//!     [6]     flags      u8    bit 0x10 = FIN, bit 0x08 = VENT (error),
//!                              bit 0x20 = IS_RESPONSE (server -> client),
//!                              other bits reserved.
//!     [7..9]  length     u24   length of payload in bytes
//!
//!   Payload:
//!     [0..1]  meta_len   u16 BE  length of meta_json in bytes
//!     [2..2+meta_len]    UTF-8 JSON object with the per-call fields
//!                        (e.g. {"start_pos":0,"seq_len":1,"layer_range":"0-14",
//!                               "request_id":"req-42","status":200,
//!                               "compute_ms":17})
//!     [2+meta_len..]     raw body bytes (packed f32 / packed u32 / status JSON)
//!
//! Framing on UDS: this binary wraps the aeon-flow frame in a 4-byte
//! length prefix (same as fat-station-uds) so a stream-oriented
//! transport can identify frame boundaries without parsing the header.
//! On a datagram transport (UDP), the prefix is dropped and one
//! datagram = one aeon-flow frame.
//!
//! NOTE: the kernel calls (NativeLlamaPipeline) are byte-for-byte the
//! same as fat-station-uds. Only the wire boundary changes.
//!
//! See: docs/pneuma/mesh-flow-unification.md

use std::io::{Read, Write};
use std::os::unix::net::{UnixListener, UnixStream};
use std::path::PathBuf;
use std::sync::{Arc, Mutex};

use distributed_inference::model::NativeLlamaPipeline;
use serde_json::{json, Value};

const NATIVE_BATCH_CAPACITY: usize = 8;

// ─────────────────────────────────────────────────────────────────────
// Aeon-flow header constants (mirror open-source/aeon/src/flow/FlowCodec.ts)
// ─────────────────────────────────────────────────────────────────────

const FLOW_HEADER_SIZE: usize = 10;
const FLOW_MAX_PAYLOAD: usize = 0xff_ffff; // u24 ceiling = 16 MiB - 1
const FLAG_FIN: u8 = 0x10;
const FLAG_VENT: u8 = 0x08;
const FLAG_RESPONSE: u8 = 0x20;

// Route opcodes carried in the `stream_id` u16. These collapse the
// HTTP-style "method + path" of fat-station-uds into a single 16-bit
// integer so the wire is constant-size and zero-allocation to dispatch.
const ROUTE_HEALTH: u16 = 0x0001;
const ROUTE_EMBED: u16 = 0x0002;
const ROUTE_FORWARD: u16 = 0x0003;
const ROUTE_LM_HEAD: u16 = 0x0004;
const ROUTE_COBORDISM_EMBED: u16 = 0x0005;
const ROUTE_COBORDISM_LM_HEAD: u16 = 0x0006;

// 4-byte UDS framing wrap (so the receiver knows how many bytes to
// pull off the byte-stream socket before parsing the aeon-flow header).
// On UDP this prefix is dropped — one datagram == one aeon-flow frame.
const UDS_FRAMING_PREFIX_SIZE: usize = 4;
const MAX_FRAME_BYTES: usize = 256 * 1024 * 1024;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Role {
    Entry,
    Mid,
    Exit,
    Both,
    Cobordism,
}

impl Role {
    fn parse(s: &str) -> Result<Self, String> {
        match s.to_lowercase().as_str() {
            "entry" => Ok(Role::Entry),
            "mid" => Ok(Role::Mid),
            "exit" => Ok(Role::Exit),
            "both" => Ok(Role::Both),
            "cobordism" => Ok(Role::Cobordism),
            other => Err(format!(
                "--role must be entry|mid|exit|both|cobordism (got '{}')",
                other
            )),
        }
    }
    fn as_str(self) -> &'static str {
        match self {
            Role::Entry => "entry",
            Role::Mid => "mid",
            Role::Exit => "exit",
            Role::Both => "both",
            Role::Cobordism => "cobordism",
        }
    }
}

#[derive(Debug)]
struct Cli {
    knot: String,
    sock: PathBuf,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
}

fn parse_range(arg: &str, name: &str) -> Result<(usize, usize), String> {
    let sep = if arg.contains("..") { ".." } else { ":" };
    let (a, b) = arg
        .split_once(sep)
        .ok_or_else(|| format!("{}: expected 'start..end' (got '{}')", name, arg))?;
    let start: usize = a
        .parse()
        .map_err(|e| format!("{}: bad start '{}': {}", name, a, e))?;
    let end: usize = b
        .parse()
        .map_err(|e| format!("{}: bad end '{}': {}", name, b, e))?;
    if end < start {
        return Err(format!(
            "{}: end must be >= start ({} < {})",
            name, end, start
        ));
    }
    Ok((start, end))
}

fn parse_cli() -> Result<Cli, String> {
    let mut args = std::env::args().skip(1);
    let mut knot: Option<String> = None;
    let mut sock: Option<PathBuf> = None;
    let mut role: Option<Role> = None;
    let mut layers: Option<(usize, usize)> = None;
    let mut vocab: Option<(usize, usize)> = None;
    while let Some(a) = args.next() {
        match a.as_str() {
            "--knot" => {
                knot = Some(args.next().ok_or("--knot requires a value")?);
            }
            "--sock" => {
                let v = args.next().ok_or("--sock requires a value")?;
                sock = Some(PathBuf::from(v));
            }
            "--role" => {
                let v = args.next().ok_or("--role requires a value")?;
                role = Some(Role::parse(&v)?);
            }
            "--layers" => {
                let v = args.next().ok_or("--layers requires a value")?;
                layers = Some(parse_range(&v, "--layers")?);
            }
            "--vocab" => {
                let v = args.next().ok_or("--vocab requires a value")?;
                vocab = Some(parse_range(&v, "--vocab")?);
            }
            "--help" | "-h" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
    }
    let knot = knot.ok_or("--knot is required")?;
    let sock = sock.ok_or("--sock is required")?;
    let role = role.ok_or("--role is required")?;
    let layers = layers.unwrap_or((0, 0));
    if role == Role::Cobordism && vocab.is_none() {
        return Err("--vocab is required when --role=cobordism".to_string());
    }
    Ok(Cli {
        knot,
        sock,
        role,
        layers,
        vocab,
    })
}

fn print_usage() {
    eprintln!(
        "fat-station-flow --knot PATH --sock PATH --role {{entry|mid|exit|both|cobordism}} \\\n  \
         --layers START..END [--vocab START..END]\n\n\
         Wire format: 4-byte UDS framing prefix + aeon-flow 10-byte header + payload.\n\
         Payload = u16BE meta_len + UTF-8 JSON meta + raw body bytes.\n\n\
         Routes (carried in stream_id):\n  \
         0x0001 health\n  \
         0x0002 embed         (entry/both)\n  \
         0x0003 forward       (entry/mid/exit/both)\n  \
         0x0004 lm-head       (exit/both)\n  \
         0x0005 cob-embed     (cobordism)\n  \
         0x0006 cob-lm-head   (cobordism)"
    );
}

// ─────────────────────────────────────────────────────────────────────
// Aeon-flow frame codec (mirror of FlowCodec.ts)
// ─────────────────────────────────────────────────────────────────────

#[derive(Debug)]
struct FlowFrame {
    stream_id: u16,
    sequence: u32,
    flags: u8,
    payload: Vec<u8>,
}

fn encode_flow_frame(frame: &FlowFrame) -> Result<Vec<u8>, String> {
    if frame.payload.len() > FLOW_MAX_PAYLOAD {
        return Err(format!(
            "payload {}B exceeds u24 max {}B",
            frame.payload.len(),
            FLOW_MAX_PAYLOAD
        ));
    }
    let mut out = Vec::with_capacity(FLOW_HEADER_SIZE + frame.payload.len());
    out.extend_from_slice(&frame.stream_id.to_be_bytes());
    out.extend_from_slice(&frame.sequence.to_be_bytes());
    out.push(frame.flags);
    let len = frame.payload.len();
    out.push(((len >> 16) & 0xff) as u8);
    out.push(((len >> 8) & 0xff) as u8);
    out.push((len & 0xff) as u8);
    out.extend_from_slice(&frame.payload);
    Ok(out)
}

fn decode_flow_frame(bytes: &[u8]) -> Result<FlowFrame, String> {
    if bytes.len() < FLOW_HEADER_SIZE {
        return Err(format!(
            "frame {}B < header {}B",
            bytes.len(),
            FLOW_HEADER_SIZE
        ));
    }
    let stream_id = u16::from_be_bytes([bytes[0], bytes[1]]);
    let sequence = u32::from_be_bytes([bytes[2], bytes[3], bytes[4], bytes[5]]);
    let flags = bytes[6];
    let length = ((bytes[7] as usize) << 16) | ((bytes[8] as usize) << 8) | (bytes[9] as usize);
    if bytes.len() < FLOW_HEADER_SIZE + length {
        return Err(format!(
            "truncated payload: declared={}B, available={}B",
            length,
            bytes.len() - FLOW_HEADER_SIZE
        ));
    }
    let payload = bytes[FLOW_HEADER_SIZE..FLOW_HEADER_SIZE + length].to_vec();
    Ok(FlowFrame {
        stream_id,
        sequence,
        flags,
        payload,
    })
}

// payload = u16BE meta_len + meta_json + body
fn encode_payload(meta: &Value, body: &[u8]) -> Vec<u8> {
    let meta_str = meta.to_string();
    let meta_bytes = meta_str.as_bytes();
    let mut out = Vec::with_capacity(2 + meta_bytes.len() + body.len());
    let meta_len = meta_bytes.len();
    out.push(((meta_len >> 8) & 0xff) as u8);
    out.push((meta_len & 0xff) as u8);
    out.extend_from_slice(meta_bytes);
    out.extend_from_slice(body);
    out
}

fn decode_payload(payload: &[u8]) -> Result<(Value, &[u8]), String> {
    if payload.len() < 2 {
        return Err("payload < 2B (no meta-length prefix)".to_string());
    }
    let meta_len = ((payload[0] as usize) << 8) | (payload[1] as usize);
    if payload.len() < 2 + meta_len {
        return Err(format!(
            "payload {}B < 2 + meta_len {}",
            payload.len(),
            meta_len
        ));
    }
    let meta_bytes = &payload[2..2 + meta_len];
    let meta: Value =
        serde_json::from_slice(meta_bytes).map_err(|e| format!("meta json parse: {}", e))?;
    let body = &payload[2 + meta_len..];
    Ok((meta, body))
}

// ─────────────────────────────────────────────────────────────────────
// UDS read / write — wraps aeon-flow frame in 4-byte length prefix so
// a stream-oriented socket can identify frame boundaries. On a datagram
// socket (UDP) the prefix is dropped.
// ─────────────────────────────────────────────────────────────────────

fn read_framed(stream: &mut UnixStream) -> Result<FlowFrame, String> {
    let mut len_buf = [0u8; UDS_FRAMING_PREFIX_SIZE];
    stream
        .read_exact(&mut len_buf)
        .map_err(|e| format!("read len prefix: {}", e))?;
    let total_len = u32::from_be_bytes(len_buf) as usize;
    if total_len == 0 || total_len > MAX_FRAME_BYTES {
        return Err(format!("frame length {} out of bounds", total_len));
    }
    let mut buf = vec![0u8; total_len];
    stream
        .read_exact(&mut buf)
        .map_err(|e| format!("read frame body ({}B): {}", total_len, e))?;
    decode_flow_frame(&buf)
}

fn write_framed(stream: &mut UnixStream, frame: &FlowFrame) -> Result<(), String> {
    let body = encode_flow_frame(frame)?;
    if body.len() > MAX_FRAME_BYTES {
        return Err(format!("frame too large: {}B", body.len()));
    }
    let len_prefix = (body.len() as u32).to_be_bytes();
    stream
        .write_all(&len_prefix)
        .map_err(|e| format!("write len prefix: {}", e))?;
    stream
        .write_all(&body)
        .map_err(|e| format!("write frame: {}", e))?;
    stream.flush().map_err(|e| format!("flush: {}", e))?;
    Ok(())
}

fn write_error(stream: &mut UnixStream, sequence: u32, stream_id: u16, status: u16, msg: &str) {
    eprintln!("[fat-station-flow] error {}: {}", status, msg);
    let meta = json!({ "status": status, "error": msg });
    let payload = encode_payload(&meta, &[]);
    let _ = write_framed(
        stream,
        &FlowFrame {
            stream_id,
            sequence,
            flags: FLAG_RESPONSE | FLAG_FIN | FLAG_VENT,
            payload,
        },
    );
}

// ─────────────────────────────────────────────────────────────────────
// Body codecs — packed little-endian f32 / u32 (mirror fat-station-uds)
// ─────────────────────────────────────────────────────────────────────

fn body_to_f32(body: &[u8]) -> Result<Vec<f32>, String> {
    if !body.len().is_multiple_of(4) {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed f32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0.0f32; n];
    for i in 0..n {
        let off = i * 4;
        let word = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
        out[i] = f32::from_bits(word);
    }
    Ok(out)
}

fn body_to_u32(body: &[u8]) -> Result<Vec<u32>, String> {
    if !body.len().is_multiple_of(4) {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed u32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0u32; n];
    for i in 0..n {
        let off = i * 4;
        out[i] = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
    }
    Ok(out)
}

fn f32_to_body(arr: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_bits().to_le_bytes());
    }
    out
}

// ─────────────────────────────────────────────────────────────────────
// Handlers
// ─────────────────────────────────────────────────────────────────────

struct Station {
    pipeline: Mutex<NativeLlamaPipeline>,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
    vocab_size: usize,
    hidden_dim: usize,
}

fn meta_str(meta: &Value, key: &str) -> Option<String> {
    meta.get(key).and_then(|v| {
        v.as_str()
            .map(|s| s.to_string())
            .or_else(|| v.as_u64().map(|n| n.to_string()))
    })
}

fn meta_usize(meta: &Value, key: &str) -> Result<usize, String> {
    meta.get(key)
        .and_then(|v| v.as_u64())
        .map(|n| n as usize)
        .ok_or_else(|| format!("missing or non-integer meta field '{}'", key))
}

fn meta_layer_range(meta: &Value) -> Result<(usize, usize), String> {
    let raw = meta
        .get("layer_range")
        .and_then(|v| v.as_str())
        .ok_or_else(|| "missing meta field 'layer_range'".to_string())?;
    let (a, b) = raw
        .split_once('-')
        .ok_or_else(|| format!("layer_range='{}': expected 'start-end'", raw))?;
    let s: usize = a.parse().map_err(|e| format!("layer_range start: {}", e))?;
    let e: usize = b.parse().map_err(|e| format!("layer_range end: {}", e))?;
    Ok((s, e))
}

fn ok_response(
    stream: &mut UnixStream,
    sequence: u32,
    stream_id: u16,
    body: Vec<u8>,
    request_id: &str,
    compute_ms: u128,
) {
    let meta = json!({
        "status": 200,
        "request_id": request_id,
        "compute_ms": compute_ms as u64,
    });
    let payload = encode_payload(&meta, &body);
    let _ = write_framed(
        stream,
        &FlowFrame {
            stream_id,
            sequence,
            flags: FLAG_RESPONSE | FLAG_FIN,
            payload,
        },
    );
}

fn handle_health(station: &Station, stream: &mut UnixStream, sequence: u32) {
    let layers = format!("{}-{}", station.layers.0, station.layers.1);
    let vocab = match station.vocab {
        Some((s, e)) => format!("{}-{}", s, e),
        None => "all".to_string(),
    };
    let meta = json!({
        "status": 200,
        "role": station.role.as_str(),
        "layers": layers,
        "vocab": vocab,
        "vocab_size": station.vocab_size,
        "hidden_dim": station.hidden_dim,
        "transport": "aeon-flow/uds",
    });
    let payload = encode_payload(&meta, &[]);
    let _ = write_framed(
        stream,
        &FlowFrame {
            stream_id: ROUTE_HEALTH,
            sequence,
            flags: FLAG_RESPONSE | FLAG_FIN,
            payload,
        },
    );
}

fn handle_embed(station: &Station, frame: FlowFrame, stream: &mut UnixStream) {
    let seq = frame.sequence;
    if !matches!(station.role, Role::Entry | Role::Both) {
        write_error(
            stream,
            seq,
            ROUTE_EMBED,
            404,
            &format!("/embed not available on role={}", station.role.as_str()),
        );
        return;
    }
    let (meta, body) = match decode_payload(&frame.payload) {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_EMBED, 400, &e),
    };
    let request_id = meta_str(&meta, "request_id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match meta_usize(&meta, "start_pos") {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_EMBED, 400, &e),
    };
    let tokens = match body_to_u32(body) {
        Ok(t) => t,
        Err(e) => return write_error(stream, seq, ROUTE_EMBED, 400, &e),
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.embed_chunk(&tokens, start_pos)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            eprintln!(
                "[fat-station-flow] embed tokens={} start_pos={} -> {}f32 in {} ms",
                tokens.len(),
                start_pos,
                out.len(),
                t0.elapsed().as_millis()
            );
            ok_response(
                stream,
                seq,
                ROUTE_EMBED,
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            );
        }
        Ok(Err(e)) => write_error(
            stream,
            seq,
            ROUTE_EMBED,
            500,
            &format!("embed error: {}", e),
        ),
        Err(e) => write_error(
            stream,
            seq,
            ROUTE_EMBED,
            500,
            &format!("embed panicked: {:?}", panic_payload(&e)),
        ),
    }
}

fn handle_forward(station: &Station, frame: FlowFrame, stream: &mut UnixStream) {
    let seq = frame.sequence;
    if matches!(station.role, Role::Cobordism) {
        write_error(
            stream,
            seq,
            ROUTE_FORWARD,
            404,
            "/forward not available on cobordism shard",
        );
        return;
    }
    let (meta, body) = match decode_payload(&frame.payload) {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_FORWARD, 400, &e),
    };
    let request_id = meta_str(&meta, "request_id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match meta_usize(&meta, "start_pos") {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_FORWARD, 400, &e),
    };
    let seq_len = match meta_usize(&meta, "seq_len") {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_FORWARD, 400, &e),
    };
    let layer_range = match meta_layer_range(&meta) {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_FORWARD, 400, &e),
    };
    let residual = match body_to_f32(body) {
        Ok(r) => r,
        Err(e) => return write_error(stream, seq, ROUTE_FORWARD, 400, &e),
    };
    if seq_len == 0 || seq_len > NATIVE_BATCH_CAPACITY {
        write_error(
            stream,
            seq,
            ROUTE_FORWARD,
            400,
            &format!(
                "seq_len {} out of range (0, {}]",
                seq_len, NATIVE_BATCH_CAPACITY
            ),
        );
        return;
    }
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.forward_range_chunk(&residual, layer_range.0, layer_range.1, start_pos, seq_len)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            eprintln!(
                "[fat-station-flow] forward layers=[{},{}) seq_len={} start_pos={} residual_in={} residual_out={} in {} ms",
                layer_range.0, layer_range.1, seq_len, start_pos,
                residual.len(), out.len(), t0.elapsed().as_millis()
            );
            ok_response(
                stream,
                seq,
                ROUTE_FORWARD,
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            );
        }
        Ok(Err(e)) => write_error(
            stream,
            seq,
            ROUTE_FORWARD,
            500,
            &format!("forward error: {}", e),
        ),
        Err(e) => write_error(
            stream,
            seq,
            ROUTE_FORWARD,
            500,
            &format!("forward panicked: {:?}", panic_payload(&e)),
        ),
    }
}

fn handle_lm_head(station: &Station, frame: FlowFrame, stream: &mut UnixStream) {
    let seq = frame.sequence;
    if !matches!(station.role, Role::Exit | Role::Both) {
        write_error(
            stream,
            seq,
            ROUTE_LM_HEAD,
            404,
            &format!("/lm-head not available on role={}", station.role.as_str()),
        );
        return;
    }
    let (meta, body) = match decode_payload(&frame.payload) {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_LM_HEAD, 400, &e),
    };
    let request_id = meta_str(&meta, "request_id").unwrap_or_else(|| "no-id".to_string());
    let seq_len = match meta_usize(&meta, "seq_len") {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_LM_HEAD, 400, &e),
    };
    let residual = match body_to_f32(body) {
        Ok(r) => r,
        Err(e) => return write_error(stream, seq, ROUTE_LM_HEAD, 400, &e),
    };
    if seq_len == 0 || seq_len > NATIVE_BATCH_CAPACITY {
        write_error(
            stream,
            seq,
            ROUTE_LM_HEAD,
            400,
            &format!(
                "seq_len {} out of range (0, {}]",
                seq_len, NATIVE_BATCH_CAPACITY
            ),
        );
        return;
    }
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.lm_head_only(&residual, seq_len)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            eprintln!(
                "[fat-station-flow] lm-head seq_len={} -> {}f32 in {} ms",
                seq_len,
                out.len(),
                t0.elapsed().as_millis()
            );
            ok_response(
                stream,
                seq,
                ROUTE_LM_HEAD,
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            );
        }
        Ok(Err(e)) => write_error(
            stream,
            seq,
            ROUTE_LM_HEAD,
            500,
            &format!("lm_head error: {}", e),
        ),
        Err(e) => write_error(
            stream,
            seq,
            ROUTE_LM_HEAD,
            500,
            &format!("lm_head panicked: {:?}", panic_payload(&e)),
        ),
    }
}

fn handle_cobordism_embed(station: &Station, frame: FlowFrame, stream: &mut UnixStream) {
    let seq = frame.sequence;
    if station.role != Role::Cobordism {
        write_error(
            stream,
            seq,
            ROUTE_COBORDISM_EMBED,
            404,
            "/cob-embed only on cobordism role",
        );
        return;
    }
    let (meta, body) = match decode_payload(&frame.payload) {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_COBORDISM_EMBED, 400, &e),
    };
    let request_id = meta_str(&meta, "request_id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match meta_usize(&meta, "start_pos") {
        Ok(v) => v,
        Err(e) => return write_error(stream, seq, ROUTE_COBORDISM_EMBED, 400, &e),
    };
    let vstart = meta
        .get("vocab_start")
        .and_then(|v| v.as_u64())
        .map(|v| v as usize)
        .unwrap_or(station.vocab.unwrap().0);
    let vend = meta
        .get("vocab_end")
        .and_then(|v| v.as_u64())
        .map(|v| v as usize)
        .unwrap_or(station.vocab.unwrap().1);
    let tokens = match body_to_u32(body) {
        Ok(t) => t,
        Err(e) => return write_error(stream, seq, ROUTE_COBORDISM_EMBED, 400, &e),
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.embed_chunk_range(&tokens, start_pos, vstart, vend)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            eprintln!(
                "[fat-station-flow] cob-embed tokens={} vocab=[{},{}) -> {}f32 in {} ms",
                tokens.len(),
                vstart,
                vend,
                out.len(),
                t0.elapsed().as_millis()
            );
            ok_response(
                stream,
                seq,
                ROUTE_COBORDISM_EMBED,
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            );
        }
        Ok(Err(e)) => write_error(
            stream,
            seq,
            ROUTE_COBORDISM_EMBED,
            500,
            &format!("cob_embed error: {}", e),
        ),
        Err(e) => write_error(
            stream,
            seq,
            ROUTE_COBORDISM_EMBED,
            500,
            &format!("cob_embed panicked: {:?}", panic_payload(&e)),
        ),
    }
}

