fn panic_payload(p: &Box<dyn std::any::Any + Send>) -> String {
    if let Some(s) = p.downcast_ref::<String>() {
        s.clone()
    } else if let Some(s) = p.downcast_ref::<&'static str>() {
        s.to_string()
    } else {
        "<non-string panic payload>".to_string()
    }
}

fn dispatch(station: &Station, mut stream: UnixStream) {
    // One frame per connection — same shape as fat-station-uds. The TS
    // client opens a fresh socket per call.
    let frame = match read_framed(&mut stream) {
        Ok(f) => f,
        Err(e) => {
            // No sequence to echo because we couldn't decode the header;
            // best-effort emit a vent on stream_id=0, sequence=0.
            write_error(&mut stream, 0, 0, 400, &e);
            return;
        }
    };
    match frame.stream_id {
        ROUTE_HEALTH => handle_health(station, &mut stream, frame.sequence),
        ROUTE_EMBED => handle_embed(station, frame, &mut stream),
        ROUTE_FORWARD => handle_forward(station, frame, &mut stream),
        ROUTE_LM_HEAD => handle_lm_head(station, frame, &mut stream),
        ROUTE_COBORDISM_EMBED => handle_cobordism_embed(station, frame, &mut stream),
        ROUTE_COBORDISM_LM_HEAD => handle_cobordism_lm_head(station, frame, &mut stream),
        other => write_error(
            &mut stream,
            frame.sequence,
            other,
            404,
            &format!("no route for stream_id=0x{:04x}", other),
        ),
    }
}

// ─────────────────────────────────────────────────────────────────────
// Knot dim sniffer — same defaults as fat-station-uds.
// ─────────────────────────────────────────────────────────────────────

fn sniff_dims(path: &str) -> (usize, usize) {
    use std::fs::File;
    use std::io::Read as _;
    let Ok(mut f) = File::open(path) else {
        return (151_936, 3584);
    };
    let mut head = vec![0u8; 4 * 1024 * 1024];
    let n = f.read(&mut head).unwrap_or(0);
    if n < 16 || &head[0..4] != b"KNOT" {
        return (151_936, 3584);
    }
    let mut len_bytes = [0u8; 4];
    len_bytes.copy_from_slice(&head[6..10]);
    let metadata_length = u32::from_le_bytes(len_bytes) as usize;
    if 10 + metadata_length > n {
        return (151_936, 3584);
    }
    let Ok(meta_str) = std::str::from_utf8(&head[10..10 + metadata_length]) else {
        return (151_936, 3584);
    };
    let Ok(json) = serde_json::from_str::<serde_json::Value>(meta_str) else {
        return (151_936, 3584);
    };
    let cfg = json
        .get("config")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let vocab = cfg
        .get("vocab_size")
        .and_then(|v| v.as_u64())
        .unwrap_or(151_936) as usize;
    let hidden = cfg
        .get("hidden_dim")
        .and_then(|v| v.as_u64())
        .unwrap_or(3584) as usize;
    (vocab, hidden)
}

// ─────────────────────────────────────────────────────────────────────
// main
// ─────────────────────────────────────────────────────────────────────

fn main() {
    let cli = match parse_cli() {
        Ok(c) => c,
        Err(e) => {
            eprintln!("ERROR: {}\n", e);
            print_usage();
            std::process::exit(2);
        }
    };

    eprintln!(
        "[fat-station-flow] booting role={} layers=[{},{}) sock={} knot={}",
        cli.role.as_str(),
        cli.layers.0,
        cli.layers.1,
        cli.sock.display(),
        cli.knot
    );
    if let Some((s, e)) = cli.vocab {
        eprintln!("[fat-station-flow] vocab=[{},{})", s, e);
    }

    let t_boot = std::time::Instant::now();
    let pipeline = NativeLlamaPipeline::new(cli.knot.clone(), false, 0.9);
    eprintln!(
        "[fat-station-flow] pipeline ready in {} ms",
        t_boot.elapsed().as_millis()
    );
    let (vocab_size, hidden_dim) = sniff_dims(&cli.knot);
    eprintln!(
        "[fat-station-flow] dims: vocab_size={} hidden_dim={}",
        vocab_size, hidden_dim
    );

    let station = Arc::new(Station {
        pipeline: Mutex::new(pipeline),
        role: cli.role,
        layers: cli.layers,
        vocab: cli.vocab,
        vocab_size,
        hidden_dim,
    });

    // Remove stale socket (UDS bind fails if path exists).
    let _ = std::fs::remove_file(&cli.sock);
    let listener = match UnixListener::bind(&cli.sock) {
        Ok(l) => l,
        Err(e) => {
            eprintln!("ERROR: bind {}: {}", cli.sock.display(), e);
            std::process::exit(3);
        }
    };
    eprintln!(
        "[fat-station-flow] listening on uds://{} (aeon-flow framing)",
        cli.sock.display()
    );

    for incoming in listener.incoming() {
        match incoming {
            Ok(stream) => {
                let st = Arc::clone(&station);
                std::thread::spawn(move || {
                    dispatch(&st, stream);
                });
            }
            Err(e) => {
                eprintln!("[fat-station-flow] accept error: {}", e);
            }
        }
    }
}
